import React, { useEffect, useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [productos, setProductos] = useState([]);
  const [categoriaSeleccionada, setCategoriaSeleccionada] = useState(null);
  const [cargando, setCargando] = useState(false);

  // Buscador
  const [busqueda, setBusqueda] = useState("");

  // Modales categoría
  const [mostrarModal, setMostrarModal] = useState(false);
  const [nuevaCategoria, setNuevaCategoria] = useState({
    Nombre: "",
    Descripcion: "",
  });

  const [categoriaEditando, setCategoriaEditando] = useState(null);
  const [mostrarModalEditar, setMostrarModalEditar] = useState(false);

  // Modal producto
  const [mostrarModalProducto, setMostrarModalProducto] = useState(false);
  const [productoEditando, setProductoEditando] = useState(null);

  // Paginación
  const [paginaActual, setPaginaActual] = useState(1);
  const categoriasPorPagina = 6;

  useEffect(() => {
    obtenerCategorias();
  }, []);

  // =========================
  // CATEGORÍAS
  // =========================
  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("❌ Error al obtener categorías", error);
    }
  };

  const mostrarProductosPorCategoria = async (categoria) => {
    setCategoriaSeleccionada(categoria);
    setCargando(true);
    try {
      const res = await axios.get(
        `http://localhost:5000/api/productos/categoria/${categoria.CategoriaID}`
      );
      setProductos(res.data);
    } catch (error) {
      console.error("❌ Error al obtener productos", error);
    } finally {
      setCargando(false);
    }
  };

  const volverACategorias = () => {
    setCategoriaSeleccionada(null);
    setProductos([]);
  };

  const guardarCategoria = async (e) => {
    e.preventDefault();
    try {
      await axios.post("http://localhost:5000/api/categorias", nuevaCategoria);
      await obtenerCategorias();
      setMostrarModal(false);
    } catch (error) {
      alert("Error al guardar categoría");
    }
  };

  const actualizarCategoria = async (e) => {
    e.preventDefault();
    try {
      await axios.put(
        `http://localhost:5000/api/categorias/${categoriaEditando.CategoriaID}`,
        categoriaEditando
      );
      await obtenerCategorias();
      setMostrarModalEditar(false);
    } catch (error) {
      alert("Error al actualizar categoría");
    }
  };

  const eliminarCategoria = async (CategoriaID) => {
    if (!window.confirm("¿Eliminar categoría?")) return;
    try {
      const res = await axios.get(
        `http://localhost:5000/api/productos/categoria/${CategoriaID}`
      );
      if (res.data.length > 0) {
        alert("No se puede eliminar, tiene productos");
        return;
      }

      await axios.delete(`http://localhost:5000/api/categorias/${CategoriaID}`);
      await obtenerCategorias();
    } catch (error) {
      alert("Error al eliminar categoría");
    }
  };

  // =========================
  // PRODUCTOS
  // =========================
  const guardarProducto = async (e) => {
    e.preventDefault();
    try {
      await axios.put(
        `http://localhost:5000/api/productos/${productoEditando.ProductoID}`,
        productoEditando
      );
      mostrarProductosPorCategoria(categoriaSeleccionada);
      setMostrarModalProducto(false);
    } catch (error) {
      alert("Error al actualizar producto");
    }
  };

  const eliminarProducto = async (ProductoID) => {
    if (!window.confirm("¿Eliminar producto?")) return;
    try {
      await axios.delete(`http://localhost:5000/api/productos/${ProductoID}`);
      setProductos((prev) =>
        prev.filter((p) => p.ProductoID !== ProductoID)
      );
    } catch (error) {
      alert("Error al eliminar producto");
    }
  };

  // =========================
  // FILTRO Y PAGINACIÓN
  // =========================
  const categoriasFiltradas = categorias.filter((c) =>
    c.Nombre.toLowerCase().includes(busqueda.toLowerCase())
  );

  const totalPaginas = Math.ceil(
    categoriasFiltradas.length / categoriasPorPagina
  );

  const categoriasMostradas = categoriasFiltradas.slice(
    (paginaActual - 1) * categoriasPorPagina,
    paginaActual * categoriasPorPagina
  );

  // =========================
  // UI
  // =========================
  return (
    <div className="container mt-5">
      {!categoriaSeleccionada ? (
        <>
          <div className="d-flex justify-content-between mb-3">
            <input
              className="form-control w-50"
              placeholder="Buscar categoría"
              value={busqueda}
              onChange={(e) => setBusqueda(e.target.value)}
            />
            <button
              className="btn btn-success"
              onClick={() => setMostrarModal(true)}
            >
              ➕ Nueva categoría
            </button>
          </div>

          <div className="row">
            {categoriasMostradas.map((cat) => (
              <div key={cat.CategoriaID} className="col-md-4 mb-4">
                <div className="card p-3 shadow-sm">
                  <h5
                    className="text-primary"
                    style={{ cursor: "pointer" }}
                    onClick={() => mostrarProductosPorCategoria(cat)}
                  >
                    {cat.Nombre}
                  </h5>
                  <p className="text-muted">
                    {cat.Descripcion || "Sin descripción"}
                  </p>
                  <div className="text-end">
                    <button
                      className="btn btn-warning btn-sm me-2"
                      onClick={() => {
                        setCategoriaEditando(cat);
                        setMostrarModalEditar(true);
                      }}
                    >
                      ✏️
                    </button>
                    <button
                      className="btn btn-danger btn-sm"
                      onClick={() => eliminarCategoria(cat.CategoriaID)}
                    >
                      🗑️
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {totalPaginas > 1 && (
            <nav className="d-flex justify-content-center">
              <ul className="pagination">
                {Array.from({ length: totalPaginas }, (_, i) => (
                  <li
                    key={i}
                    className={`page-item ${
                      paginaActual === i + 1 ? "active" : ""
                    }`}
                  >
                    <button
                      className="page-link"
                      onClick={() => setPaginaActual(i + 1)}
                    >
                      {i + 1}
                    </button>
                  </li>
                ))}
              </ul>
            </nav>
          )}
        </>
      ) : (
        <>
          <div className="d-flex justify-content-between mb-3">
            <h4>Productos - {categoriaSeleccionada.Nombre}</h4>
            <button className="btn btn-secondary" onClick={volverACategorias}>
              ← Volver
            </button>
          </div>

          {cargando ? (
            <p>Cargando...</p>
          ) : (
            <table className="table table-bordered text-center">
              <thead className="table-dark">
                <tr>
                  <th>ID</th>
                  <th>Nombre</th>
                  <th>Precio</th>
                  <th>Stock</th>
                  <th>Acciones</th>
                </tr>
              </thead>
              <tbody>
                {productos.map((p) => (
                  <tr key={p.ProductoID}>
                    <td>{p.ProductoID}</td>
                    <td>{p.Nombre}</td>
                    <td>${p.Precio}</td>
                    <td>{p.Stock}</td>
                    <td>
                      <button
                        className="btn btn-warning btn-sm me-2"
                        onClick={() => {
                          setProductoEditando(p);
                          setMostrarModalProducto(true);
                        }}
                      >
                        ✏️
                      </button>
                      <button
                        className="btn btn-danger btn-sm"
                        onClick={() => eliminarProducto(p.ProductoID)}
                      >
                        🗑️
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </>
      )}
    </div>
  );
}
